#include <stdio.h>
#include <string.h>
#include <mqueue.h>
#include <fcntl.h>
#include <sys/stat.h>

int main(void) {
    struct mq_attr attr = { .mq_maxmsg = 10, .mq_msgsize = 128 };
    mqd_t mq = mq_open("/kf_mq_prio", O_CREAT | O_RDWR, 0644, &attr);

    mq_send(mq, "low", 3, 1);
    mq_send(mq, "high", 4, 3);
    mq_send(mq, "mid", 3, 2);

    for (int i = 0; i < 3; i++) {
        char buf[128];
        unsigned int prio;
        ssize_t n = mq_receive(mq, buf, sizeof(buf), &prio);
        buf[n] = '\0';
        printf("prio=%u msg=%s\n", prio, buf);
    }

    mq_close(mq);
    mq_unlink("/kf_mq_prio");
    return 0;
}

