/* == EXEMPLE =======================================
 * 2 messages avec priorites : urgent vs normal
 * ================================================= */
void example_prio(void) {
    struct mq_attr a = { .mq_maxmsg = 5, .mq_msgsize = 64 };
    mqd_t q = mq_open("/kf_ex_prio", O_CREAT|O_RDWR, 0644, &a);
    mq_send(q, "normal", 6, 1);
    mq_send(q, "urgent", 6, 5);
    char buf[64]; unsigned int p;
    for (int i = 0; i < 2; i++) {
        ssize_t n = mq_receive(q, buf, sizeof(buf), &p);
        buf[n] = '\0';
        printf("%s (p=%u)\n", buf, p);
    }
    mq_close(q); mq_unlink("/kf_ex_prio");
}
/* Resultat: urgent (p=5), normal (p=1) */

